document.getElementById("copyButton").addEventListener("click",function(){const e=document.getElementById("accountNumber").innerText;navigator.clipboard.writeText(e).then(function(){Swal.fire({title:"Success!",text:"Account number copied to clipboard!",icon:"success"})},function(e){alert("Failed to copy account number.")})});const countrySelect=document.querySelector("#country"),stateSelect=document.querySelector("#stateOfOrigin"),updateStateSelect=()=>{const e=states?.filter(e=>e.countryCode===countrySelect.value);stateSelect.disabled=!1,stateSelect.innerHTML="",e.forEach(e=>{const t=document.createElement("option");t.value=e.name,t.text=e.name,form.stateOfOrigin===e.name&&(t.selected=!0),stateSelect.appendChild(t)})};""!==form&&""!==states&&updateStateSelect(),countrySelect.addEventListener("change",updateStateSelect);